mapper.select:
select il.id, il.log_no, il.inventory_id, il.material_id, m.code as materialCode, m.name as materialName, il.warehouse_id, w.name as warehouseName, il.biz_type, il.biz_id, il.before_number, il.change_number, il.after_number, il.operator_id, il.operator_name, il.remark, il.operate_time from inventory_log il left join material m on il.material_id = m.id and m.deleted = 0 left join warehouse w on il.warehouse_id = w.id and w.deleted = 0
and il.inventory_id = #{q.inventoryId}
and il.material_id = #{q.materialId}
and il.warehouse_id = #{q.warehouseId}
and il.biz_type = #{q.bizType}
and il.operate_time between #{q.beginTime} and #{q.endTime}
order by il.operate_time desc, il.id desc
